P20_CONTENT_ORDER = [167, 168]
P21_CONTENT_ORDER = [169, 170, 171]


def seed(db_path: str) -> None:
    conn = sqlite3.connect(db_path)
    cur = conn.cursor()

    # ── Pages ─────────────────────────────────────────────────────────────────
    for pid, icon, src_pg, name_en, name_ru, name_ua in PAGES:
        cur.execute(
            "INSERT OR IGNORE INTO pages (id, icon, source_slug, source_page, linked_pages)"
            " VALUES (?,?,?,?,?)",
            (pid, icon, SOURCE_SLUG, src_pg, json.dumps([])),
        )
        for lang, name in [("en", name_en), ("ru", name_ru), ("ua", name_ua)]:
            cur.execute(
                "INSERT OR IGNORE INTO page_i18n (page_id, lang, name) VALUES (?,?,?)",
                (pid, lang, name),
            )

    # ── Attach P20 to P1 ──────────────────────────────────────────────────────
    cur.execute("SELECT linked_pages FROM pages WHERE id=1")
    row = cur.fetchone()
    linked = json.loads(row[0]) if row and row[0] else []
    if 20 not in linked:
        linked.append(20)
        cur.execute("UPDATE pages SET linked_pages=? WHERE id=1", (json.dumps(linked),))

    # ── Attach P21 to P20 ─────────────────────────────────────────────────────
    cur.execute("SELECT linked_pages FROM pages WHERE id=20")
    row = cur.fetchone()
    linked = json.loads(row[0]) if row and row[0] else []
    if 21 not in linked:
        linked.append(21)
        cur.execute("UPDATE pages SET linked_pages=? WHERE id=20", (json.dumps(linked),))

    # ── Contents ──────────────────────────────────────────────────────────────
    for item in P20_CONTENTS + P21_CONTENTS:
        dice_json = json.dumps(item["dice"]) if "dice" in item else None
        subinfo = json.dumps(item.get("subinfo_fixed", [])) if item.get("subinfo_fixed") else None
        cur.execute(
            "INSERT OR IGNORE INTO contents"
            " (id, icon, source_slug, source_page, dice, subinfo_fixed)"
            " VALUES (?,?,?,?,?,?)",
            (item["id"], item["icon"], SOURCE_SLUG, item["source_page"], dice_json, subinfo),
        )
        name_en, name_ru, name_ua = item["name"]
        desc_en, desc_ru, desc_ua = item["desc"]
        for lang, name, desc in [
            ("en", name_en, desc_en),
            ("ru", name_ru, desc_ru),
            ("ua", name_ua, desc_ua),
        ]:
            cur.execute(
                "INSERT OR IGNORE INTO content_i18n (content_id, lang, name, desc)"
                " VALUES (?,?,?,?)",
                (item["id"], lang, name, desc),
            )

    # ── page_contents ──────────────────────────────────────────────────────────
    cur.execute("DELETE FROM page_contents WHERE page_id=20")
    for sort_order, cid in enumerate(P20_CONTENT_ORDER):
        cur.execute(
            "INSERT INTO page_contents (page_id, content_id, sort_order) VALUES (?,?,?)",
            (20, cid, sort_order),
        )

    cur.execute("DELETE FROM page_contents WHERE page_id=21")
    for sort_order, cid in enumerate(P21_CONTENT_ORDER):
        cur.execute(
            "INSERT INTO page_contents (page_id, content_id, sort_order) VALUES (?,?,?)",
            (21, cid, sort_order),
        )

    conn.commit()
    conn.close()
    print("Done: Ports & Shore Leave (P20) + Contractors (P21) + C167-C171 seeded into", repr(db_path))


if __name__ == "__main__":
    seed(DB_PATH)
